SELECT total
FROM traffic_fatalities
WHERE year_id = 1;

SELECT fatality_count
FROM monthly_fatalities
WHERE year_id = 1 AND month_id = 2;

SELECT SUM(fatality_count) AS total_fatalities_in_january
FROM monthly_fatalities
WHERE month_id = 1;

SELECT SUM(total) AS total_fatalities
FROM traffic_fatalities
WHERE year_id = 1;

SELECT type_name
FROM fatality_types
WHERE severity_level = 'Severe';

SELECT total
FROM traffic_fatalities
WHERE year_id = 2023;
